enum OrderSide: String, Codable, CaseIterable {
    case buy
    case sell
}

enum OrderType: String, Codable, CaseIterable {
    case market
    case limit

    var displayName: String {
        switch self {
        case .market: return "Market"
        case .limit: return "Limit"
        }
    }
}

enum OrderStatus: String, Codable {
    case pending
    case partiallyFilled
    case filled
    case rejected
    case cancelled
}

struct TradeOrderRequest: Codable {
    let symbol: String
    let side: OrderSide
    let quantity: Int
    let type: OrderType
    let limitPrice: Decimal?
}

struct TradeOrderResponse: Codable {
    let orderId: String
    let status: OrderStatus
    let filledQuantity: Int
    let averageFillPrice: Decimal?
}

struct OrderRecord: Identifiable, Codable {
    let id: String
    let symbol: String
    let side: OrderSide
    let quantity: Int
    let type: OrderType
    let status: OrderStatus
    let timestamp: Date
}

struct Position: Identifiable, Codable {
    var id: String { symbol }
    let symbol: String
    var quantity: Int
    var averageCost: Decimal
    var currentPrice: Decimal

    var marketValue: Decimal {
        Decimal(quantity) * currentPrice
    }

    var unrealizedPnL: Decimal {
        (currentPrice - averageCost) * Decimal(quantity)
    }
}

struct Quote: Codable {
    let symbol: String
    let bid: Decimal
    let ask: Decimal
    let lastPrice: Decimal
    let change: Decimal
    let changePercent: Decimal
    let timestamp: Date
}

final class PortfolioStore: ObservableObject {
    @Published private(set) var positions: [Position] = [
        Position(symbol: "AAPL", quantity: 25, averageCost: 178.40, currentPrice: 182.15),
        Position(symbol: "MSFT", quantity: 12, averageCost: 402.10, currentPrice: 410.55)
    ]
    @Published private(set) var orders: [OrderRecord] = []

    private var cancellables = Set<AnyCancellable>()

    var totalMarketValue: Decimal {
        positions.reduce(0) { $0 + $1.marketValue }
    }

    var totalUnrealizedPnL: Decimal {
        positions.reduce(0) { $0 + $1.unrealizedPnL }
    }

    func bind(tradeService: TradeService) {
        tradeService.orderEvents
            .receive(on: DispatchQueue.main)
            .sink { [weak self] event in
                self?.handle(order: event)
            }
            .store(in: &cancellables)
    }

    private func handle(order: ExecutedOrderEvent) {
        let record = OrderRecord(
            id: order.orderId,
            symbol: order.symbol,
            side: order.side,
            quantity: order.filledQuantity,
            type: order.type,
            status: order.status,
            timestamp: order.timestamp
        )
        orders.insert(record, at: 0)

        guard order.status == .filled || order.status == .partiallyFilled else { return }
        let fillQty = order.filledQuantity
        let fillPrice = order.averageFillPrice ?? 0

        if let index = positions.firstIndex(where: { $0.symbol == order.symbol }) {
            var position = positions[index]
            switch order.side {
            case .buy:
                let totalCost = (position.averageCost * Decimal(position.quantity)) + (fillPrice * Decimal(fillQty))
                let newQty = position.quantity + fillQty
                position.quantity = newQty
                position.averageCost = newQty > 0 ? totalCost / Decimal(newQty) : 0
            case .sell:
                position.quantity = max(0, position.quantity - fillQty)
                if position.quantity == 0 {
                    position.averageCost = 0
                }
            }
            positions[index] = position
        } else if order.side == .buy {
            positions.append(Position(symbol: order.symbol, quantity: fillQty, averageCost: fillPrice, currentPrice: fillPrice))
        }
    }
}

struct ExecutedOrderEvent {
    let orderId: String
    let symbol: String
    let side: OrderSide
    let type: OrderType
    let status: OrderStatus
    let filledQuantity: Int
    let averageFillPrice: Decimal?
    let timestamp: Date
}

final class TradeService {
    let orderEvents = PassthroughSubject<ExecutedOrderEvent, Never>()
    private let apiClient: SecureAPIClient

    init(apiClient: SecureAPIClient) {
        self.apiClient = apiClient
    }

    func execute(order: TradeOrderRequest) async throws -> TradeOrderResponse {
        let response: TradeOrderResponse = try await apiClient.send(
            path: "/v1/trades/execute",
            method: .post,
            body: order
        )

        let event = ExecutedOrderEvent(
            orderId: response.orderId,
            symbol: order.symbol,
            side: order.side,
            type: order.type,
            status: response.status,
            filledQuantity: response.filledQuantity,
            averageFillPrice: response.averageFillPrice,
            timestamp: Date()
        )
        orderEvents.send(event)
        return response
    }
}

final class MarketDataService: ObservableObject {
    @Published private(set) var isConnected = false
    @Published private var quotes: [String: Quote] = [:]

    private var timer: AnyCancellable?

    func connect(symbols: [String]) {
        isConnected = true
        seedQuotes(symbols: symbols)
        timer = Timer.publish(every: 1.2, on: .main, in: .common)
            .autoconnect()
            .sink { [weak self] _ in
                self?.updateQuotes(symbols: symbols)
            }
    }

    func disconnect() {
        timer?.cancel()
        timer = nil
        isConnected = false
    }

    func quote(for symbol: String) -> Quote? {
        quotes[symbol]
    }

    private func seedQuotes(symbols: [String]) {
        let basePrices: [String: Decimal] = [
            "AAPL": 182.15,
            "MSFT": 410.55,
            "TSLA": 176.20,
            "NVDA": 903.40,
            "AMZN": 180.80
        ]

        for symbol in symbols {
            let price = basePrices[symbol] ?? 100
            quotes[symbol] = Quote(
                symbol: symbol,
                bid: price - 0.05,
                ask: price + 0.05,
                lastPrice: price,
                change: 0,
                changePercent: 0,
                timestamp: Date()
            )
        }
    }

    private func updateQuotes(symbols: [String]) {
        for symbol in symbols {
            guard let current = quotes[symbol] else { continue }
            let delta = Decimal(Double.random(in: -1.5...1.5))
            let newPrice = max(1, current.lastPrice + delta)
            let change = newPrice - current.lastPrice
            let changePercent = current.lastPrice == 0 ? 0 : (change / current.lastPrice) * 100
            quotes[symbol] = Quote(
                symbol: symbol,
                bid: newPrice - 0.05,
                ask: newPrice + 0.05,
                lastPrice: newPrice,
                change: change,
                changePercent: changePercent,
                timestamp: Date()
            )
        }
    }
}

final class SecureAPIClient {
    private let baseURL: URL
    private let session: URLSession
    private let keychain = KeychainService()

    init(baseURL: URL, session: URLSession = .shared) {
        self.baseURL = baseURL
        let config = URLSessionConfiguration.ephemeral
        config.waitsForConnectivity = true
        config.timeoutIntervalForRequest = 15
        config.timeoutIntervalForResource = 30
        self.session = URLSession(configuration: config)
    }

    func send<T: Decodable, U: Encodable>(path: String, method: HTTPMethod, body: U? = nil) async throws -> T {
        var request = URLRequest(url: baseURL.appendingPathComponent(path))
        request.httpMethod = method.rawValue
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.setValue("application/json", forHTTPHeaderField: "Accept")
        request.setValue(signature(for: path), forHTTPHeaderField: "X-Signature")
        request.setValue(timestamp(), forHTTPHeaderField: "X-Timestamp")

        if let token = keychain.read(key: "api_key"), !token.isEmpty {
            request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        }

        if let body = body {
            request.httpBody = try JSONEncoder().encode(body)
        }

        do {
            let (data, response) = try await session.data(for: request)
            guard let http = response as? HTTPURLResponse else {
                throw APIError.invalidResponse
            }
            guard 200..<300 ~= http.statusCode else {
                if let serverError = try? JSONDecoder().decode(ServerErrorResponse.self, from: data) {
                    throw APIError.server(serverError.message)
                }
                throw APIError.httpStatus(http.statusCode)
            }
            return try JSONDecoder().decode(T.self, from: data)
        } catch let error as APIError {
            throw error
        } catch {
            if path == "/v1/trades/execute", let simulated: T = simulateTradeResponse(body: body) {
                return simulated
            }
            throw APIError.network(error.localizedDescription)
        }
    }

    private func simulateTradeResponse<T, U>(body: U?) -> T? {
        guard T.self == TradeOrderResponse.self, let order = body as? TradeOrderRequest else { return nil }
        let fillPrice: Decimal = order.limitPrice ?? Decimal(Double.random(in: 100...500))
        let response = TradeOrderResponse(
            orderId: UUID().uuidString,
            status: .filled,
            filledQuantity: order.quantity,
            averageFillPrice: fillPrice
        )
        return response as? T
    }

    private func signature(for path: String) -> String {
        let secret = keychain.read(key: "api_secret") ?? "local-dev-secret"
        let payload = "\(path)|\(timestamp())"
        let key = SymmetricKey(data: Data(secret.utf8))
        let signature = HMAC<SHA256>.authenticationCode(for: Data(payload.utf8), using: key)
        return Data(signature).base64EncodedString()
    }

    private func timestamp() -> String {
        String(Int(Date().timeIntervalSince1970))
    }
}

enum HTTPMethod: String {
    case get = "GET"
    case post = "POST"
    case put = "PUT"
    case delete = "DELETE"
}

enum APIError: LocalizedError {
    case invalidResponse
    case httpStatus(Int)
    case server(String)
    case network(String)

    var errorDescription: String? {
        switch self {
        case .invalidResponse:
            return "Invalid server response."
        case .httpStatus(let code):
            return "Request failed with status \(code)."
        case .server(let message):
            return message
        case .network(let message):
            return "Network error: \(message)"
        }
    }
}

struct ServerErrorResponse: Codable {
    let message: String
}

final class SessionManager {
    private let keychain = KeychainService()

    func saveAPIKey(_ key: String) {
        keychain.save(key: "api_key", value: key)
    }

    func saveAPISecret(_ secret: String) {
        keychain.save(key: "api_secret", value: secret)
    }
}

final class KeychainService {
    func save(key: String, value: String) {
        let data = Data(value.utf8)
        let query: [CFString: Any] = [
            kSecClass: kSecClassGenericPassword,
            kSecAttrAccount: key,
            kSecValueData: data
        ]
        SecItemDelete(query as CFDictionary)
        SecItemAdd(query as CFDictionary, nil)
    }

    func read(key: String) -> String? {
        let query: [CFString: Any] = [
            kSecClass: kSecClassGenericPassword,
            kSecAttrAccount: key,
            kSecReturnData: true,
            kSecMatchLimit: kSecMatchLimitOne
        ]
        var item: CFTypeRef?
        let status = SecItemCopyMatching(query as CFDictionary, &item)
        guard status == errSecSuccess, let data = item as? Data else { return nil }
        return String(data: data, encoding: .utf8)
    }
}

extension Decimal {
    var currencyString: String {
        let formatter = NumberFormatter()
        formatter.numberStyle = .currency
        return formatter.string(from: self as NSDecimalNumber) ?? "$0.00"
    }

    var signedCurrencyString: String {
        let value = self as NSDecimalNumber
        let formatter = NumberFormatter()
        formatter.numberStyle = .currency
        formatter.positivePrefix = "+"
        return formatter.string(from: value) ?? "$0.00"
    }

    var percentString: String {
        let formatter = NumberFormatter()
        formatter.numberStyle = .percent
        formatter.maximumFractionDigits = 2
        return formatter.string(from: ((self / 100) as NSDecimalNumber)) ?? "0%"
    }
}